batchProcessing.template:
var targetFiles = [];

function addFiles(files) {
    for (var i = 0; i < files.length; ++i) {
        if (File.exists(files[i]))
            targetFiles.push(files[i]);
    }
}

function processFiles() {
    for (var i = 0; i < targetFiles.length; ++i) {
        console.writeln("Processing: " + targetFiles[i]);

        var windows = ImageWindow.open(targetFiles[i]);
        if (windows.length == 0)
            continue;

        var window = windows[0];
        var view = window.mainView;

        // Process the image
        view.beginProcess();
        // ... your processing code ...
        view.endProcess();

        // Save and close
        var outputPath = File.changeExtension(targetFiles[i], ".processed.xisf");
        window.saveAs(outputPath, false, false, false);
        window.forceClose();
    }
}

