dialogTemplateV8.template:
#engine v8

#feature-id    MyDialog : Utilities > My Dialog
#feature-info  A dialog example.

CoreApplication.ensureMinimumVersion( 1, 9, 4 );

// Use a class expression so re-running the script in a long-lived runtime is safe.
var MyDialog = class extends Dialog
{
   constructor()
   {
      super();
      this.windowTitle = "My Script";

      this.label = new Label( this );
      this.label.text = "Hello World";

      this.okButton = new PushButton( this );
      this.okButton.text = "OK";
      this.okButton.onClick = () => this.ok();

      this.cancelButton = new PushButton( this );
      this.cancelButton.text = "Cancel";
      this.cancelButton.onClick = () => this.cancel();

      let buttons = new HorizontalSizer;
      buttons.addStretch();
      buttons.add( this.okButton );
      buttons.addSpacing( 8 );
      buttons.add( this.cancelButton );

      this.sizer = new VerticalSizer;
      this.sizer.margin = 8;
      this.sizer.spacing = 8;
      this.sizer.add( this.label );
      this.sizer.addStretch();
      this.sizer.add( buttons );

      this.adjustToContents();
   }
};

(new MyDialog).execute();

imageProcessingV8.template:
#engine v8

CoreApplication.ensureMinimumVersion( 1, 9, 4 );

(() =>
{
   console.show();

   let window = ImageWindow.activeWindow;
   if ( window.isNull )
   {
      console.criticalln( "No active image window." );
      return;
   }

   let view = window.currentView;
   view.beginProcess( UndoFlag.PixelData );
   try
   {
      let image = view.image;

      // Iterate the image at near-native speed.
      for ( let c = 0; c < image.numberOfNominalChannels; ++c )
      {
         let i = new ImageIterator( image, c );
         for ( let y = 0, h = i.height; y < h; ++y )
            for ( let x = 0, w = i.width; x < w; ++x )
               i[y][x] = FMath.mtf( 0.5, i[y][x] );
      }
   }
   catch ( error )
   {
      console.criticalln( "Error: " + error.message );
   }
   view.endProcess();
})();

starDetectionV8.template:
#engine v8

CoreApplication.ensureMinimumVersion( 1, 9, 4 );

(() =>
{
   console.show();

   let image = ImageWindow.activeWindow.mainView.image;
   image.statusEnabled = true;

   let D = new StarDetector;
   D.fitPSF = true;

   let stars = D.stars( image );
   console.writeln( format( "* %u stars detected.", stars.length ) );

   let P = PSF.fitStars( image, stars, PSFunction.Auto );
   console.writeln( format( "* %u valid PSF fits.", P.length ) );

   for ( let i = 0; i < Math.min( P.length, 10 ); ++i )
   {
      let p = P[i];
      console.writeln( format( "  star %3u: x=%.2f y=%.2f FWHM=%.2fx%.2f signal=%.3e",
         i, p.x, p.y, p.fwhmX, p.fwhmY, p.signal ) );
   }
})();
